import json, re

def parse_json(raw):
    if not isinstance(raw, str): return {}
    s = re.sub(r'^```(?:json)?\s*|\s*```$', '', raw.strip(), flags=re.DOTALL)
    m = re.search(r'\{.*\}', s, re.DOTALL)
    if not m: return {}
    try: return json.loads(m.group(0))
    except Exception: return {}

def main(inputs, storages):
    topic = (inputs.get('RESEARCH_TOPIC') or '').strip()
    raw = inputs.get('PLANNER', '')
    plan = parse_json(raw)

    prev = inputs.get('PARSE_PLAN') or {}
    if isinstance(prev, dict) and 'output' in prev: prev = prev['output']
    prev_iter = prev.get('iteration', -1) if isinstance(prev, dict) else -1
    iteration = prev_iter + 1

    web_queries, paper_queries, pdf_urls, llm_prompts = [], [], [], []
    for a in (plan.get('actions') or []):
        if not isinstance(a, dict): continue
        tool = a.get('tool')
        if tool == 'web_search' and a.get('query'):
            web_queries.append(a['query'])
        elif tool == 'paper_search' and a.get('query'):
            paper_queries.append(a['query'])
        elif tool == 'pdf_read' and a.get('url'):
            pdf_urls.append(a['url'])
        elif tool == 'llm' and a.get('prompt'):
            llm_prompts.append(a['prompt'])

    return {'output': {
        'iteration': iteration,
        'topic': topic,
        'reasoning': plan.get('reasoning', ''),
        'web_queries': web_queries,
        'paper_queries': paper_queries,
        'pdf_urls': pdf_urls,
        'llm_prompts': llm_prompts,
        'action_count': len(plan.get('actions') or [])
    }}

import io, hashlib, time, requests

def hid(s): return hashlib.sha256(s.encode('utf-8')).hexdigest()[:16]

def db_get(db, k):
    if not db: return None
    try: return db.get(k)
    except Exception: return None

def db_store(db, key, value, metadata=None):
    """Auto-embed write. Falls back to put() if backend lacks store()."""
    if not db: return False
    md = metadata or {}
    try:
        db.store(key=key, value=value, metadata=md)
        return True
    except Exception:
        try:
            db.put(key, {'value': value, 'metadata': md})
            return True
        except Exception:
            return False

def db_search(db, query, limit=10):
    if not db: return []
    try:
        return db.search(query, limit=limit) or []
    except Exception:
        return []

def get_record(db, k):
    """Backend-agnostic source reader. Handles both store() (value+metadata) and put() (flat dict) shapes."""
    rec = db_get(db, k)
    if not isinstance(rec, dict): return None
    if 'value' in rec and isinstance(rec.get('metadata'), dict):
        return {**rec['metadata'], 'content': rec.get('value', '') or ''}
    return rec

def extract(url):
    try:
        from pypdf import PdfReader
        r = requests.get(url, timeout=30, headers={'User-Agent': 'flowgraph-research/1.0'})
        r.raise_for_status()
        rd = PdfReader(io.BytesIO(r.content))
        return '\n'.join((p.extract_text() or '') for p in rd.pages[:60])[:40000]
    except Exception as e:
        return f'[pdf error: {e}]'

def main(inputs, storages):
    plan = inputs.get('PARSE_PLAN', {})
    if isinstance(plan, dict) and 'output' in plan: plan = plan['output']
    urls = plan.get('pdf_urls', []) if isinstance(plan, dict) else []
    iteration = plan.get('iteration', 0) if isinstance(plan, dict) else 0

    db = storages.get('vectordb') if storages else None
    if not urls:
        return {'output': {'tool': 'pdf_read', 'iteration': iteration, 'urls': [], 'results': [], 'count': 0, 'skipped': True}}

    results = []
    for url in urls[:4]:
        h = hid(url)
        cached = get_record(db, f'source:{h}')
        if cached:
            results.append({'hash': h, 'cached': True, 'type': 'pdf', 'url': url})
            continue
        text = extract(url)
        metadata = {
            'type': 'pdf', 'url': url, 'title': url.rsplit('/', 1)[-1],
            'found_via': 'planner', 'iteration': iteration, 'fetched_at': int(time.time())
        }
        db_store(db, f'source:{h}', text, metadata=metadata)
        results.append({'hash': h, 'cached': False, 'type': 'pdf', 'url': url, 'preview': text[:400]})

    return {'output': {'tool': 'pdf_read', 'iteration': iteration, 'urls': urls, 'results': results, 'count': len(results), 'skipped': False}}

