ARXIV_NS = {
    'atom': 'http://www.w3.org/2005/Atom',
    'arxiv': 'http://arxiv.org/schemas/atom'
}

def arxiv_search(q, k=5):
    try:
        r = requests.get('http://export.arxiv.org/api/query', params={
            'search_query': f'all:{q}',
            'max_results': k,
            'sortBy': 'relevance',
            'sortOrder': 'descending'
        }, timeout=20, headers={'User-Agent': 'flowgraph-research/1.0'})
        r.raise_for_status()
        root = ET.fromstring(r.text)
        out = []
        for entry in root.findall('atom:entry', ARXIV_NS):
            id_el = entry.find('atom:id', ARXIV_NS)
            arxiv_id = id_el.text.rsplit('/', 1)[-1] if (id_el is not None and id_el.text) else ''
            title_el = entry.find('atom:title', ARXIV_NS)
            title = ' '.join((title_el.text or '').split()) if title_el is not None else ''
            sum_el = entry.find('atom:summary', ARXIV_NS)
            summary = ' '.join((sum_el.text or '').split()) if sum_el is not None else ''
            authors = []
            for a in entry.findall('atom:author', ARXIV_NS):
                ne = a.find('atom:name', ARXIV_NS)
                if ne is not None and ne.text:
                    authors.append(ne.text)
            pub_el = entry.find('atom:published', ARXIV_NS)
            published = pub_el.text if pub_el is not None else ''
            pdf_url = ''
            for link in entry.findall('atom:link', ARXIV_NS):
                if link.get('title') == 'pdf':
                    pdf_url = link.get('href', '')
                    break
            if not pdf_url and arxiv_id:
                pdf_url = f'https://arxiv.org/pdf/{arxiv_id}'
            abs_url = f'https://arxiv.org/abs/{arxiv_id}' if arxiv_id else ''
            out.append({
                'arxiv_id': arxiv_id, 'title': title, 'abstract': summary,
                'authors': authors[:8], 'pdf_url': pdf_url, 'abs_url': abs_url,
                'published': published
            })
        return out
    except Exception as e:
        return [{'error': str(e), 'query': q}]

def fetch_pdf_text(url):
    try:
        from pypdf import PdfReader
        r = requests.get(url, timeout=30, headers={'User-Agent': 'flowgraph-research/1.0'})
        r.raise_for_status()
        rd = PdfReader(io.BytesIO(r.content))
        return '\n'.join((p.extract_text() or '') for p in rd.pages[:60])[:100000]
    except Exception as e:
        return f'[pdf error: {e}]'

def main(inputs, storages):
    plan = inputs.get('PARSE_PLAN', {})
    if isinstance(plan, dict) and 'output' in plan: plan = plan['output']
    queries = plan.get('paper_queries', []) if isinstance(plan, dict) else []
    iteration = plan.get('iteration', 0) if isinstance(plan, dict) else 0

    db = storages.get('vector_db') if storages else None

    if not queries:
        return {'output': {'tool': 'paper_search', 'iteration': iteration, 'queries': [], 'results': [], 'count': 0, 'skipped': True}}

    results = []
    for q in queries[:4]:
        papers = arxiv_search(q, k=5)
        for paper in papers[:3]:
            if 'error' in paper: continue
            pdf_url = paper.get('pdf_url') or ''
            if not pdf_url: continue
            h = hid(pdf_url)
            cached = get_record(db, f'source:{h}')
            if cached:
                results.append({
                    'hash': h, 'cached': True, 'type': 'paper',
                    'url': pdf_url, 'title': paper.get('title', ''),
                    'arxiv_id': paper.get('arxiv_id', ''), 'query': q
                })
                continue
            text = fetch_pdf_text(pdf_url)
            # Embed the abstract+body together so semantic search hits both summary-level and detail-level queries.
            searchable = f"{paper.get('title','')}\n\n{paper.get('abstract','')}\n\n{text}"
            metadata = {
                'type': 'paper', 'url': pdf_url,
                'abs_url': paper.get('abs_url', ''),
                'title': paper.get('title', ''),
                'arxiv_id': paper.get('arxiv_id', ''),
                'authors': paper.get('authors', []),
                'abstract': paper.get('abstract', ''),
                'published': paper.get('published', ''),
                'found_via': q, 'iteration': iteration, 'fetched_at': int(time.time())
            }
            db_store(db, f'source:{h}', searchable, metadata=metadata)
            preview_parts = []
            if metadata['abstract']:
                preview_parts.append('ABSTRACT: ' + metadata['abstract'])
            preview_parts.append('FULLTEXT: ' + text)
            results.append({
                'hash': h, 'cached': False, 'type': 'paper',
                'url': pdf_url, 'title': metadata['title'],
                'arxiv_id': metadata['arxiv_id'], 'authors': metadata['authors'][:3],
                'published': metadata['published'], 'query': q,
                'preview': ' | '.join(preview_parts)
            })

    return {'output': {
        'tool': 'paper_search', 'iteration': iteration,
        'queries': queries, 'results': results, 'count': len(results),
        'skipped': False
    }}

