    if not isinstance(rec, dict): return None
    if 'value' in rec and isinstance(rec.get('metadata'), dict):
        return {**rec['metadata'], 'content': rec.get('value', '') or ''}
    return rec

def tavily(q, key, k=5):
    if not key: return [], [], 'no_key'
    try:
        r = requests.post('https://api.tavily.com/search', json={
            'api_key': key, 'query': q, 'max_results': k,
            'include_raw_content': True, 'include_images': True,
            'include_image_descriptions': True, 'search_depth': 'advanced'
        }, timeout=25)
        r.raise_for_status()
        d = r.json()
        return d.get('results', []) or [], d.get('images', []) or [], None
    except Exception as e:
        return [], [], str(e)

def ddg(q, k=5):
    """DuckDuckGo fallback. Snippets only — no full-page raw_content."""
    try:
        try:
            from ddgs import DDGS
        except ImportError:
            from duckduckgo_search import DDGS
    except ImportError as e:
        return [], [], f'ddg unavailable: {e}'
    items, imgs = [], []
    try:
        with DDGS() as d:
            for r in d.text(q, max_results=k):
                url = r.get('href') or r.get('url') or ''
                if not url: continue
                items.append({
                    'url': url,
                    'title': r.get('title', '') or '',
                    'content': (r.get('body') or ''),
                    'raw_content': ''
                })
    except Exception as e:
        return [], [], f'ddg text error: {e}'
    try:
        with DDGS() as d:
            for im in d.images(q, max_results=5):
                iurl = im.get('image') or im.get('url') or ''
                if iurl:
                    imgs.append({'url': iurl, 'description': im.get('title', '') or ''})
    except Exception:
        pass
    return items, imgs, None

def search_with_fallback(q, tavily_key, k=5):
    items, imgs, err = tavily(q, tavily_key, k)
    provider = 'tavily'
    if not items:
        ditems, dimgs, derr = ddg(q, k)
        if ditems:
            items = ditems
            imgs = imgs or dimgs
            provider = 'duckduckgo'
        else:
            provider = f'none(tavily={err},ddg={derr})'
    return items, imgs, provider

def main(inputs, storages):
    plan = inputs.get('PARSE_PLAN', {})
    if isinstance(plan, dict) and 'output' in plan: plan = plan['output']
    queries = plan.get('web_queries', []) if isinstance(plan, dict) else []
    iteration = plan.get('iteration', 0) if isinstance(plan, dict) else 0

    db = storages.get('vector_db') if storages else None
    key = os.environ.get('TAVILY_API_KEY', '')

    results = []
    providers_used = []
    if not queries:
        return {'output': {'tool': 'web_search', 'iteration': iteration, 'queries': [], 'results': [], 'count': 0, 'skipped': True, 'providers_used': []}}

    for q in queries[:6]:
        items, imgs, provider = search_with_fallback(q, key)
        providers_used.append({'query': q, 'provider': provider, 'item_count': len(items)})
        for x in items:
            url = x.get('url', '')
            if not url: continue
            h = hid(url)
            cached = get_record(db, f'source:{h}')
            if cached:
                results.append({'hash': h, 'cached': True, 'type': 'web', 'url': url, 'title': x.get('title', '') or '', 'query': q, 'provider': provider})
                continue
            content = (x.get('raw_content') or x.get('content') or '')[:25000]
            metadata = {
                'type': 'web', 'url': url, 'title': x.get('title', '') or '',
                'found_via': q, 'iteration': iteration, 'provider': provider, 'fetched_at': int(time.time())
            }
            db_store(db, f'source:{h}', content, metadata=metadata)
            results.append({'hash': h, 'cached': False, 'type': 'web', 'url': url, 'title': metadata['title'], 'query': q, 'provider': provider, 'preview': content[:400]})
        for img in imgs[:5]:
            if isinstance(img, str):
                iurl, desc = img, ''
            elif isinstance(img, dict):
                iurl = img.get('url') or ''
                desc = img.get('description') or ''
            else:
                continue
            if not iurl: continue
            ih = hid(iurl)
            if not get_record(db, f'image:{ih}'):
                # value=description so the image is searchable by what it depicts; metadata holds the URL.
                db_store(db, f'image:{ih}', desc or iurl, metadata={
                    'type': 'image', 'url': iurl, 'description': desc, 'found_via': q,
                    'iteration': iteration, 'provider': provider, 'fetched_at': int(time.time())
                })
            results.append({'hash': ih, 'type': 'image', 'url': iurl, 'query': q, 'provider': provider})

    return {'output': {
        'tool': 'web_search', 'iteration': iteration,
        'queries': queries, 'results': results, 'count': len(results),
        'skipped': False, 'providers_used': providers_used
    }}

import json, re

def _u(x):
    if isinstance(x, dict) and 'output' in x: return x['output']
    return x if isinstance(x, dict) else {}

def parse_json(raw):
    if not isinstance(raw, str): return {}
    s = re.sub(r'^```(?:json)?\s*|\s*```$', '', raw.strip(), flags=re.DOTALL)
    m = re.search(r'\{.*\}', s, re.DOTALL)
    if not m: return {}
    try: return json.loads(m.group(0))
    except Exception: return {}

def main(inputs, storages):
    web = _u(inputs.get('WEB_SEARCH'))
    paper = _u(inputs.get('PAPER_SEARCH'))
    pdf = _u(inputs.get('PDF_READ'))
    llm_raw = inputs.get('LLM_ACTION', '')
    llm = parse_json(llm_raw) if isinstance(llm_raw, str) else {}

    iteration = web.get('iteration', paper.get('iteration', pdf.get('iteration', 0)))

    web_count = web.get('count', 0)
    paper_count = paper.get('count', 0)
    pdf_count = pdf.get('count', 0)
    llm_answers = llm.get('answers', []) or []

    new_hashes = []
    for tool_out in (web, paper, pdf):
        for r in (tool_out.get('results') or []):
            if not r.get('cached') and r.get('hash'):
                new_hashes.append(r['hash'])

    found_anything = (web_count + paper_count + pdf_count) > 0 or bool(llm_answers)

    return {'output': {
        'iteration': iteration,
        'web_count': web_count,
        'paper_count': paper_count,
        'pdf_count': pdf_count,
        'llm_answers': llm_answers,
        'llm_response_raw': llm_raw if isinstance(llm_raw, str) else '',
        'new_source_hashes': new_hashes,
        'found_anything': found_anything,
        'message': f'iter={iteration} web={web_count} paper={paper_count} pdf={pdf_count} llm={len(llm_answers)} new_sources={len(new_hashes)}'
    }}

