            clean_claims.append(c)
        cleaned_perspectives.append({**p, 'claims': clean_claims})

    perspective_keys = []
    for i, p in enumerate(cleaned_perspectives):
        angle = (p.get('angle') or f'angle_{i}').strip()
        slug = re.sub(r'[^a-z0-9]+', '_', angle.lower()).strip('_')[:40] or f'p{i}'
        pk = f'perspective:{topic_hash}:{run_id}:iter{iteration}:{slug}'
        # Embed the perspective summary so future runs can semantically retrieve prior angles.
        searchable = f"{angle}\n\n{p.get('summary','')}"
        db_store(db, pk, searchable, metadata={
            'type': 'perspective', 'topic': topic, 'topic_hash': topic_hash, 'run_id': run_id,
            'iteration': iteration, 'angle': angle,
            'claims': p.get('claims', []) or []
        })
        perspective_keys.append(pk)

    raw_used = parsed.get('source_hashes_used', []) or []
    used = [h for h in raw_used if (not valid_hashes) or h in valid_hashes]

    iter_key = f'iteration:{topic_hash}:{run_id}:{iteration}'
    db_store(db, iter_key, parsed.get('definitive_answer', '') or '(none)', metadata={
        'type': 'iteration', 'topic': topic, 'run_id': run_id, 'iteration': iteration,
        'perspective_keys': perspective_keys,
        'open_questions': parsed.get('open_questions', []) or [],
        'source_hashes_used': used
    })
    db_store(db, f'research:latest:{topic_hash}', topic, metadata={
        'type': 'latest_pointer', 'run_id': run_id, 'topic': topic,
        'updated_at': int(time.time()), 'last_iteration': iteration
    })

    cum_persp = ((prev.get('perspectives') or []) + cleaned_perspectives)[-30:]
    cum_hashes = list(dict.fromkeys((prev.get('cumulative_source_hashes') or []) + used))
    all_persp_keys = (prev.get('all_perspective_keys') or []) + perspective_keys
    all_iter_keys = (prev.get('all_iteration_keys') or []) + [iter_key]

    return {'output': {
        'topic': topic,
        'topic_hash': topic_hash,
        'run_id': run_id,
        'iteration': iteration,
        'perspectives': cum_persp,
        'definitive_answer': parsed.get('definitive_answer', ''),
        'open_questions': parsed.get('open_questions', []) or [],
        'cumulative_source_hashes': cum_hashes,
        'all_perspective_keys': all_persp_keys,
        'all_iteration_keys': all_iter_keys,
        'fabricated_hashes_dropped': len(raw_used) - len(used)
    }}

import json, time, hashlib

def hid(s): return hashlib.sha256(s.encode('utf-8')).hexdigest()[:16]

def db_get(db, k):
    if not db: return None
    try: return db.get(k)
    except Exception: return None

def db_store(db, key, value, metadata=None):
    """Auto-embed write. Falls back to put() if backend lacks store()."""
    if not db: return False
    md = metadata or {}
    try:
        db.store(key=key, value=value, metadata=md)
        return True
    except Exception:
        try:
            db.put(key, {'value': value, 'metadata': md})
            return True
        except Exception:
            return False

def db_search(db, query, limit=10):
    if not db: return []
    try:
        return db.search(query, limit=limit) or []
    except Exception:
        return []

def get_record(db, k):
    """Backend-agnostic source reader. Handles both store() (value+metadata) and put() (flat dict) shapes."""
    rec = db_get(db, k)
    if not isinstance(rec, dict): return None
    if 'value' in rec and isinstance(rec.get('metadata'), dict):
        return {**rec['metadata'], 'content': rec.get('value', '') or ''}
    return rec

def main(inputs, storages):
    topic = (inputs.get('RESEARCH_TOPIC') or '').strip()
    final_md = inputs.get('FINAL_REPORT', '')
    db = storages.get('vector_db') if storages else None

    topic_hash = hid(topic) if topic else 'unknown'
    latest = get_record(db, f'research:latest:{topic_hash}') if db else None
    run_id = (latest or {}).get('run_id') if isinstance(latest, dict) else None

    state = {}
    if db and run_id:
        for n in range(20, -1, -1):
            rec = get_record(db, f'iteration:{topic_hash}:{run_id}:{n}')
            if isinstance(rec, dict) and rec:
                state = rec
                break

    if not run_id:
        run_id = f'{topic_hash}:{int(time.time())}'

    final_key = f'research:final:{run_id}'
    report_md = final_md if isinstance(final_md, str) else json.dumps(final_md)
    metadata = {
        'type': 'final_report', 'topic': topic, 'topic_hash': topic_hash, 'run_id': run_id,
        'created_at': int(time.time()),
        'iterations_run': (state.get('iteration', 0) or 0) + 1,
        'definitive_answer': state.get('content') or state.get('definitive_answer', ''),
        'open_questions_remaining': state.get('open_questions', []) or [],
        'perspective_keys': state.get('perspective_keys', []) or [],
        'all_source_hashes': state.get('source_hashes_used', []) or []
    }
    db_store(db, final_key, report_md, metadata=metadata)
    db_store(db, f'research:latest:{topic_hash}', topic, metadata={
        'type': 'latest_pointer', 'run_id': run_id, 'final_key': final_key,
        'topic': topic, 'updated_at': int(time.time())
    })

    return {'output': {
        'topic': topic, 'topic_hash': topic_hash, 'run_id': run_id,
        'final_key': final_key,
        'iterations_run': metadata['iterations_run'],
        'open_questions_remaining': metadata['open_questions_remaining'],
        'report_markdown': report_md
    }}

config.prompt:
You are the planner of an iterative research agent.

Topic: {RESEARCH_TOPIC}

PRIOR ITERATION STATE (empty/missing on first pass = this is iteration 0):
- Iteration just completed: {STORE_ITER.output.iteration}
- Definitive answer so far: {STORE_ITER.output.definitive_answer}
- Open questions still unresolved: {STORE_ITER.output.open_questions}
- Perspectives gathered so far: {STORE_ITER.output.perspectives}
- Sources already consulted (hashes): {STORE_ITER.output.cumulative_source_hashes}

Available tools:
- web_search — current events, news, blogs, general info. Pass {"tool":"web_search","query":"..."}.
- paper_search — research papers via arXiv. Returns paper metadata AND extracts full PDF text. Use for: technical/scientific questions, primary sources, peer-reviewed evidence, recent academic work. Pass {"tool":"paper_search","query":"..."}.
- pdf_read — deep-read a specific PDF you've already located by URL (non-arXiv: gov reports, white papers, standards docs). Pass {"tool":"pdf_read","url":"https://..."}.
- llm — synthesize from your own knowledge, no fetch. Pass {"tool":"llm","prompt":"..."}.

Decision rules:
- If the prior iteration state is empty or missing, this is the FIRST pass. Use the topic to seed 2-4 broad starting queries — mix web_search with paper_search if the topic has any technical/scientific dimension.
- On non-first passes, target the OPEN QUESTIONS specifically. Do NOT repeat queries that already produced sources you can see in cumulative_source_hashes.
- Mix tools — don't pile everything into web_search. If a question is conceptual or factual without primary-source needs, use llm. If it needs rigorous evidence, use paper_search. If you've located a specific non-arXiv PDF URL in earlier sources (e.g. a referenced report), use pdf_read.
- Pick 3-6 actions total. Quality over quantity.

Respond ONLY with JSON in this exact shape:
{
  "actions": [
    {"tool": "web_search", "query": "specific query"},
    {"tool": "paper_search", "query": "specific paper-worthy query"},
    {"tool": "pdf_read", "url": "https://..."},
    {"tool": "llm", "prompt": "specific question to answer from training"}
  ],
  "reasoning": "1-2 sentences on why these actions for this iteration"
}
